using HaCreator.MapEditor;
using HaCreator.MapEditor.Instance;
using HaCreator.MapEditor.UndoRedo;
using System;
using System.Collections.Generic;
using System.Windows;
using System.Windows.Controls;
namespace HaCreator.GUI.InstanceEditor { public partial class ObjectInstanceEditor : EditorBase { public ObjectInstance item; public ObjectInstanceEditor(ObjectInstance item) { InitializeComponent(); this.item = item; Set(xInput, item.X); Set(yInput, item.Y); Set(zInput, item.Z); rBox.IsChecked = item.r; flipBox.IsChecked = item.Flip; hideBox.IsChecked = item.hide.HasValue && item.hide.Value; dynamicBox.IsChecked = item.Dynamic; flowBox.IsChecked = item.flow; reactorBox.IsChecked = item.reactor; pathLabel.Text = HaCreatorStateManager.CreateItemDescription(item); nameEnable.IsChecked = item.Name != null; nameBox.Text = item.Name ?? string.Empty; Load(item.rx, rxBox, rxInt); Load(item.ry, ryBox, ryInt); Load(item.cx, cxBox, cxInt); Load(item.cy, cyBox, cyInt); tagsEnable.IsChecked = item.tags != null; tagsBox.Text = item.tags ?? string.Empty; questEnable.IsChecked = item.QuestInfo != null; if (item.QuestInfo != null) foreach (var q in item.QuestInfo) questList.Items.Add(q); UpdateOptional(); } private static void Set(TextBox b, int v) => InstanceEditorDialogSupport.SetInt(b, v); private static void Load(int? v, CheckBox c, TextBox b) { c.IsChecked = v.HasValue; if (v.HasValue) Set(b, v.Value); } private static int? Opt(CheckBox c, TextBox b) => c.IsChecked == true ? InstanceEditorDialogSupport.GetInt(b) : null; protected override void cancelButton_Click(object s, EventArgs e) => Close(); protected override void okButton_Click(object s, EventArgs e) { lock (item.Board.ParentControl) { int x = InstanceEditorDialogSupport.GetInt(xInput, item.X), y = InstanceEditorDialogSupport.GetInt(yInput, item.Y), z = InstanceEditorDialogSupport.GetInt(zInput, item.Z); List<UndoRedoAction> a = new(); if (x != item.X || y != item.Y) { a.Add(UndoRedoManager.ItemMoved(item, new Microsoft.Xna.Framework.Point(item.X, item.Y), new Microsoft.Xna.Framework.Point(x, y))); item.Move(x, y); } if (z != item.Z) { a.Add(UndoRedoManager.ItemZChanged(item, item.Z, z)); item.Z = z; item.Board.BoardItems.Sort(); } if (a.Count > 0) item.Board.UndoRedoMan.AddUndoBatch(a); item.Name = nameEnable.IsChecked == true ? nameBox.Text : null; item.flow = flowBox.IsChecked == true; item.reactor = reactorBox.IsChecked == true; item.Dynamic = dynamicBox.IsChecked == true; item.r = rBox.IsChecked == true; item.Flip = flipBox.IsChecked == true; item.hide = hideBox.IsChecked == true; item.rx = Opt(rxBox, rxInt); item.ry = Opt(ryBox, ryInt); item.cx = Opt(cxBox, cxInt); item.cy = Opt(cyBox, cyInt); item.tags = tagsEnable.IsChecked == true ? tagsBox.Text : null; if (questEnable.IsChecked == true) { List<ObjectInstanceQuest> q = new(); foreach (ObjectInstanceQuest info in questList.Items) q.Add(info); item.QuestInfo = q; } else item.QuestInfo = null; } Close(); } private void Optional_Changed(object s, RoutedEventArgs e) => UpdateOptional(); private void UpdateOptional() { if (nameBox == null) return; nameBox.IsEnabled = nameEnable.IsChecked == true; rxInt.IsEnabled = rxBox.IsChecked == true; ryInt.IsEnabled = ryBox.IsChecked == true; cxInt.IsEnabled = cxBox.IsChecked == true; cyInt.IsEnabled = cyBox.IsChecked == true; tagsBox.IsEnabled = tagsEnable.IsChecked == true; bool q = questEnable.IsChecked == true; questList.IsEnabled = questAdd.IsEnabled = questRemove.IsEnabled = q; } private void QuestRemove_Click(object s, RoutedEventArgs e) { if (questList.SelectedIndex >= 0) questList.Items.RemoveAt(questList.SelectedIndex); } private void QuestAdd_Click(object s, RoutedEventArgs e) { ObjQuestInput input = new() { Owner = this }; if (input.ShowDialog() == true) questList.Items.Add(input.result); } private void Cancel_Click(object s, RoutedEventArgs e) => cancelButton_Click(s, EventArgs.Empty); private void Ok_Click(object s, RoutedEventArgs e) => okButton_Click(s, EventArgs.Empty); } }
